code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Avatar } from 'decantr/components';

code.example:
function Testimonials() {
  const { div, p, span } = tags;
  const items = [
    { quote: 'This product transformed our workflow completely.', avatar: '', name: 'Sarah Johnson', role: 'CTO at TechCorp' },
    { quote: 'The best investment we made this year.', avatar: '', name: 'Mike Chen', role: 'Product Lead at Acme' },
    { quote: 'Incredible support team and amazing features.', avatar: '', name: 'Lisa Park', role: 'Engineering Manager at Globex' }
  ];

  return div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6 _py8') },
    ...items.map(t =>
      Card({ class: css('_flex _col _gap4') },
        Card.Body({},
          p({ class: css('_italic _fgmuted') }, `"${t.quote}"`),
          div({ class: css('_flex _aic _gap3 _mt3') },
            Avatar({ src: t.avatar, name: t.name }),
            div({},
              span({ class: css('_textsm _bold') }, t.name),
              span({ class: css('_textxs _fgmuted _block') }, t.role)
            )
          )
        )
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Avatar, createScrollReveal } from 'decantr/components';
import { onMount, onDestroy } from 'decantr/core';

code.example:
function TestimonialWall({ items }) {
  const { div, p, span, h2 } = tags;

  const section = div({ class: css('_flex _col _gap8 _py12') },
    h2({ class: css('_heading2 _tc') }, 'Loved by developers'),
    div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap4') },
      ...items.map((t, i) => {
        const card = Card({ class: css('d-reveal _flex _col _gap4') },
          Card.Body({},
            p({ class: css('_italic _fgmuted') }, `"${t.quote}"`),
            div({ class: css('_flex _aic _gap3 _mt3') },
              Avatar({ src: t.avatar, name: t.name, size: 'sm' }),
              div({},
                span({ class: css('_textsm _bold') }, t.name),
                span({ class: css('_textxs _fgmuted _block') }, t.role)
              )
            )
          )
        );
        card.style.setProperty('--d-i', String(i));
        return card;
      })
    )
  );
  return section;
}

